// TRF_PrepareFormatterInput - Prepare structured items for the formatter agent
// V2: Separação de notas da agenda + mascaramento de dados sensíveis
const input = $('TRG_FromOrchestrator').item.json;

let envelope = input.envelope || {};
if (!envelope.from_phone) {
  try { envelope = $json.envelope || {}; } catch(e) {}
}

const agentResponse = input.agent_response || {};
const queryMeta = input.query_meta || {};
const items = agentResponse.items || [];
const queryType = queryMeta.query_type || 'general';
const tz = queryMeta.tz || 'America/Belem';
const dateRangeLabel = queryMeta.date_range_label || '';
const userMessage = (input.user_message || envelope.user_message || '').toLowerCase();

// --- SEPARAR ITENS POR TIPO ---
const scheduleItems = []; // reminders, tasks (têm data/hora)
const noteItems = [];     // notes (informação salva)

for (const item of items) {
  if (item.type === 'note') {
    noteItems.push(item);
  } else {
    scheduleItems.push(item);
  }
}

// --- DETECTAR INTENÇÃO DO USUÁRIO ---
const sensitiveKeywords = ['senha', 'password', 'login', 'código', 'codigo', 'pin', 'acesso', 'credencial'];
const noteQueryKeywords = ['nota', 'notas', 'anotação', 'anotações', 'salvo', 'salvei', 'guardei', 'guardado'];
const scheduleKeywords = ['agenda', 'programação', 'programacao', 'compromisso', 'semana', 'hoje', 'amanhã', 'amanha', 'horário', 'horario', 'lembrete', 'reunião', 'reuniao'];

const isSensitiveQuery = sensitiveKeywords.some(k => userMessage.includes(k));
const isNoteQuery = noteQueryKeywords.some(k => userMessage.includes(k)) || isSensitiveQuery;
const isScheduleQuery = scheduleKeywords.some(k => userMessage.includes(k));

// Determinar qual conjunto de itens enviar ao agente
let relevantItems;
let queryContext;

if (isNoteQuery && !isScheduleQuery) {
  // Pergunta sobre notas/senhas -> só notas
  relevantItems = noteItems;
  queryContext = 'note_query';
} else if (isScheduleQuery && !isNoteQuery) {
  // Pergunta sobre agenda -> só agenda, SEM notas
  relevantItems = scheduleItems;
  queryContext = 'schedule_query';
} else if (!isScheduleQuery && !isNoteQuery) {
  // Pergunta genérica -> verificar se parece busca de info específica
  // Se a mensagem parece uma pergunta sobre informação (qual, quanto, como)
  const infoKeywords = ['qual', 'quanto', 'como', 'onde', 'quem', 'nome', 'telefone', 'endereço', 'endereco', 'email', 'wi-fi', 'wifi', 'placa'];
  const isInfoQuery = infoKeywords.some(k => userMessage.includes(k));

  if (isInfoQuery && noteItems.length > 0) {
    relevantItems = noteItems;
    queryContext = 'note_query';
  } else {
    // Default: só agenda
    relevantItems = scheduleItems;
    queryContext = 'schedule_query';
  }
} else {
  // Ambos (ex: "qual minha agenda e minhas notas?") -> tudo, mas notas separadas
  relevantItems = items;
  queryContext = 'mixed_query';
}

// --- MASCARAR DADOS SENSÍVEIS EM NOTAS ---
function isSensitiveNote(note) {
  // Verificar pelo campo is_sensitive do banco OU por keywords no título/valor
  if (note.is_sensitive === true) return true;
  const title = (note.title || '').toLowerCase();
  const value = (note.value || note.content || '').toLowerCase();
  const combined = title + ' ' + value;
  return sensitiveKeywords.some(k => combined.includes(k));
}

function maskValue(value) {
  if (!value) return '***';
  const len = value.length;
  if (len <= 2) return '*'.repeat(len);
  if (len <= 4) return value.substring(0, 1) + '*'.repeat(len - 1);
  // Mostrar primeiros 3 chars e últimos 2 chars para facilitar reconhecimento
  const visibleStart = Math.min(3, Math.ceil(len * 0.3));
  const visibleEnd = Math.min(2, Math.ceil(len * 0.2));
  const masked = len - visibleStart - visibleEnd;
  return value.substring(0, visibleStart) + '*'.repeat(Math.max(masked, 2)) + value.substring(len - visibleEnd);
}

// Processar notas: mascarar se sensível
const processedItems = relevantItems.map(item => {
  if (item.type === 'note' && isSensitiveNote(item)) {
    return {
      ...item,
      _sensitive: true,
      _original_value: item.value,
      value: maskValue(item.value || item.content || ''),
      content: maskValue(item.value || item.content || '')
    };
  }
  return item;
});

const hasSensitiveNotes = processedItems.some(i => i._sensitive);
const isEmpty = (!processedItems || processedItems.length === 0);
const itemsJson = isEmpty ? '[]' : JSON.stringify(processedItems, null, 0);

return [{
  json: {
    envelope: envelope,
    trace_id: envelope.trace_id || '',
    query_type: queryType,
    query_context: queryContext,
    date_range_label: dateRangeLabel,
    tz: tz,
    items: processedItems,
    items_json: itemsJson,
    user_message: input.user_message || envelope.user_message || '',
    is_empty: isEmpty,
    has_sensitive_notes: hasSensitiveNotes,
    total_notes: noteItems.length,
    total_schedule: scheduleItems.length
  }
}];

