// TRF_FormatOutput - Extract formatted text and return standard envelope
let input;
try {
  input = $('TRF_PrepareFormatterInput').item.json;
} catch (e) {
  input = $json;
}

let formattedText = '';

// Get Agent output
let agentOutput = null;
try {
  agentOutput = $('Agent_QueryFormatter').item.json;
} catch (e) {}

if (agentOutput) {
  // Extract text from Agent output
  try {
    if (agentOutput.formatted_text) {
      formattedText = agentOutput.formatted_text;
    } else if (agentOutput.output) {
      let out = agentOutput.output;
      if (typeof out === 'string') {
        out = out.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
        try {
          const parsed = JSON.parse(out);
          formattedText = parsed.formatted_text || parsed.text || out;
        } catch (pe) {
          formattedText = out;
        }
      } else if (typeof out === 'object') {
        formattedText = out.formatted_text || out.text || JSON.stringify(out);
      }
    } else if (agentOutput.text) {
      formattedText = agentOutput.text;
    }
  } catch (e) {
    formattedText = agentOutput.output || agentOutput.text || '';
  }
}

// Fallback if Agent returned nothing useful
if (!formattedText || formattedText.length < 5) {
  if (input.is_empty) {
    formattedText = 'Tudo tranquilo por aqui! 😊 Não encontrei nenhum compromisso registrado. Quer que eu crie algum lembrete?';
  } else {
    formattedText = 'Não foi possível formatar a agenda. Tente novamente.';
  }
}

return [{
  json: {
    envelope: input.envelope || {},
    agent_response: {
      text: formattedText,
      agent: 'QUERY_FORMATTER',
      items_count: (input.items || []).length
    }
  }
}];
